export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    if (url.pathname.startsWith('/api/')) {
      const headers = new Headers(request.headers);
      headers.set('X-Internal-Auth', env.INTERNAL_SECRET || '');
      try { return await env.SERVICE_BACK.fetch(new Request(request, { headers })); }
      catch (e) { return new Response('{"error":"Service indisponible"}', { status: 502, headers: { 'Content-Type': 'application/json' } }); }
    }
    if (url.pathname === '/admin.css') return new Response(ADMIN_CSS, { headers: { 'Content-Type': 'text/css; charset=utf-8', 'Cache-Control': 'public, max-age=300' } });
    if (url.pathname === '/admin.js') return new Response(ADMIN_JS, { headers: { 'Content-Type': 'application/javascript; charset=utf-8', 'Cache-Control': 'public, max-age=300' } });
    if (url.pathname === '/favicon.svg') return new Response(FAVICON, { headers: { 'Content-Type': 'image/svg+xml; charset=utf-8', 'Cache-Control': 'public, max-age=86400' } });
    return new Response(HTML, { headers: { 'Content-Type': 'text/html; charset=utf-8' } });
  }
};

const ADMIN_CSS = "/* Admin v2 â Seed to Bloom â charte Ãcrin (refonte : aÃĐrÃĐ, sans bordures, marron) */\n:root{\n  --terre:#412F21; --terre-600:#6b533b; --terre-400:#8a6f54; --terre-200:#c8b29a;\n  --nuit:#1C1205; --nuit-700:#2a1d10;\n  --glycine:#E4D1FE; --glycine-50:#f7efff; --glycine-700:#a98bd6; --glycine-900:#6c4ea4;\n  --brume:#F0E8FF; --paille:#F2E5C2; --paille-200:#fbf3d8;\n  --bone:#ffffff; --bone-d:#eae5dc; --card:#fffefb; --surface:#efe7d7; --surface-2:#f6f1e7;\n  --text:#412F21; --muted:#96805f; --border:#eae5dc;\n  --red:#9b3a2e; --orange:#c9952f; --green:#5d7a52;\n  --font-display:'Cormorant Garamond','EB Garamond',Georgia,serif;\n  --font-body:'Alegreya',Georgia,serif;\n  --font-micro:'Inter Tight',ui-sans-serif,system-ui,sans-serif;\n  --radius:18px; --sw:248px;\n  --shadow-1:0 6px 26px -18px rgba(28,18,5,0.30);\n  --shadow-2:0 18px 44px -22px rgba(28,18,5,0.34);\n}\n*{box-sizing:border-box;margin:0;padding:0}\nbody{font-family:var(--font-body);font-synthesis:none;background:var(--surface);color:var(--text);font-size:16px;line-height:1.5}\nbutton,input,textarea,select{font-family:inherit;font-size:14px}\na{color:var(--glycine-900)}\n.spin{width:34px;height:34px;border:3px solid rgba(28,18,5,0.12);border-top-color:var(--terre);border-radius:50%;animation:spin .8s linear infinite}\n@keyframes spin{to{transform:rotate(360deg)}}\n.center{min-height:100vh;display:flex;align-items:center;justify-content:center;flex-direction:column;gap:14px;background:var(--surface)}\n.micro{font-family:var(--font-micro);font-size:10px;letter-spacing:0.12em;text-transform:uppercase;color:var(--muted)}\n\n/* login */\n.login{min-height:100vh;display:flex;align-items:center;justify-content:center;background:var(--surface);padding:24px}\n.login__card{width:100%;max-width:380px;background:var(--card);border-radius:20px;box-shadow:var(--shadow-2);padding:40px 34px;display:flex;flex-direction:column;gap:16px}\n.login__title{text-align:center;font-family:var(--font-display);font-style:italic;font-size:28px;color:var(--terre)}\n.login__logo{color:var(--terre);width:118px;margin:0 auto}\n.login__logo svg{width:100%;height:auto;display:block}\n.login__sub{text-align:center;font-family:var(--font-micro);font-size:10px;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);margin-top:-10px}\n\n/* fields */\n.field{display:flex;flex-direction:column;gap:6px;margin-bottom:4px}\n.field label{font-family:var(--font-micro);font-size:10px;letter-spacing:0.1em;text-transform:uppercase;color:var(--muted);font-weight:600}\n.inp{width:100%;padding:11px 13px;border:1px solid transparent;border-radius:11px;background:var(--surface-2);color:var(--text);outline:none;transition:box-shadow .15s,background .15s}\n.inp:focus{background:var(--bone);box-shadow:0 0 0 2px var(--glycine-700)}\ntextarea.inp{resize:vertical;min-height:64px;font-family:var(--font-body)}\n.err{display:none;color:var(--red);font-size:13px;text-align:center;background:rgba(155,58,46,0.08);padding:9px;border-radius:10px}\n\n/* buttons */\n.btn{display:inline-flex;align-items:center;gap:7px;justify-content:center;padding:11px 19px;border-radius:11px;border:none;cursor:pointer;font-family:var(--font-micro);font-size:11px;font-weight:600;letter-spacing:0.08em;text-transform:uppercase;background:var(--glycine);color:var(--terre);transition:filter .15s,transform .15s}\n.btn:hover{filter:brightness(0.97);transform:translateY(-1px)}\n.btn:disabled{opacity:0.55;cursor:default;transform:none}\n.btn--dark{background:var(--terre);color:var(--paille)}\n.btn--outline{background:var(--surface-2);color:var(--terre)}\n.btn--sm{padding:7px 13px;font-size:10px}\n.btn--danger{background:rgba(155,58,46,0.10);color:var(--red)}\n.btn--block{width:100%}\n\n/* shell */\n.shell{display:flex;min-height:100vh}\n.side{width:var(--sw);flex-shrink:0;background:var(--nuit);color:var(--paille);display:flex;flex-direction:column;position:sticky;top:0;height:100vh;overflow-y:auto}\n.notiffab{position:fixed;bottom:22px;right:22px;z-index:60;width:54px;height:54px;border-radius:50%;border:none;cursor:pointer;background:var(--terre);color:var(--paille);align-items:center;justify-content:center;box-shadow:0 6px 20px rgba(28,18,5,0.28);transition:transform .15s,filter .15s}\n.notiffab:hover{transform:translateY(-2px);filter:brightness(1.08)}\n.notiffab__c{position:absolute;top:-4px;right:-4px;min-width:21px;height:21px;padding:0 5px;border-radius:999px;background:var(--red);color:#fff;font-family:var(--font-micro);font-size:11px;font-weight:700;display:flex;align-items:center;justify-content:center;box-shadow:0 0 0 2px var(--bg,#fff)}\n.notifpanel{position:fixed;bottom:86px;right:22px;z-index:60;width:340px;max-width:calc(100vw - 44px);background:var(--card,#fff);border:1px solid var(--bone-d);border-radius:16px;box-shadow:0 12px 40px rgba(28,18,5,0.22);overflow:hidden}\n@media(max-width:760px){.notiffab{bottom:16px;right:16px}.notifpanel{bottom:80px;right:16px}}\n.side__brand{padding:24px 22px}\n.side__brand .n{font-family:var(--font-display);font-style:italic;font-size:22px;color:var(--paille)}\n.side__logo{color:var(--paille);width:96px}\n.side__logo svg{width:100%;height:auto;display:block}\n.side__brand .s{font-family:var(--font-micro);font-size:9px;letter-spacing:0.2em;text-transform:uppercase;color:rgba(242,229,194,0.55);margin-top:2px}\n.side__nav{flex:1;padding:10px 12px;display:flex;flex-direction:column;gap:3px}\n.navgroup__label{font-family:var(--font-micro);font-size:9px;font-weight:700;letter-spacing:0.14em;text-transform:uppercase;color:rgba(242,229,194,0.42);padding:14px 13px 5px}\n.navitem{display:flex;align-items:center;gap:10px;padding:10px 13px;border-radius:11px;border:none;background:none;color:rgba(242,229,194,0.78);cursor:pointer;text-align:left;width:100%;font-family:var(--font-micro);font-size:12px;letter-spacing:0.05em;text-transform:uppercase;transition:background .15s}\n.navitem:hover{background:rgba(242,229,194,0.08);color:var(--paille)}\n.navitem.active{background:rgba(242,229,194,0.14);color:var(--paille);font-weight:600}\n.side__foot{padding:16px}\n.main{flex:1;min-width:0;background:var(--surface)}\n.topbar{position:sticky;top:0;z-index:10;background:rgba(239,231,215,0.82);backdrop-filter:blur(10px);padding:22px 40px 16px;display:flex;align-items:center;gap:12px}\n.topbar__head{display:flex;flex-direction:column;gap:3px;min-width:0}\n.topbar h1{font-family:var(--font-display);font-style:italic;font-size:30px;color:var(--terre);font-weight:400;line-height:1.05}\n.topbar__sub{font-family:var(--font-micro);font-size:11.5px;letter-spacing:0.02em;color:var(--muted);line-height:1.3}\n.topbar .right{margin-left:auto;display:flex;gap:10px;flex-shrink:0}\n.wrap{padding:14px 40px 90px;max-width:1120px;margin:0 auto}\n\n/* cards / grid */\n.card{background:var(--card);border-radius:var(--radius);padding:26px 28px;margin-bottom:22px;box-shadow:var(--shadow-1)}\n.card h3{font-family:var(--font-display);font-style:italic;font-size:23px;color:var(--terre);font-weight:400;margin-bottom:14px}\n.infocard h3{display:flex;align-items:center;gap:0}\n.infocard__dot{display:none}\n.infocard__act{font-family:var(--font-micro);font-size:10.5px;letter-spacing:0.06em;text-transform:uppercase;color:var(--muted)}\n.infocard__act.is-on{color:#5d7a52}\n.admconfirm{position:fixed;inset:0;z-index:1000;background:rgba(28,18,5,0.42);display:flex;align-items:center;justify-content:center;padding:24px;animation:admcf 140ms ease}\n@keyframes admcf{from{opacity:0}to{opacity:1}}\n.admconfirm__box{background:var(--card);border-radius:20px;box-shadow:0 24px 60px rgba(28,18,5,0.32);padding:26px 28px;max-width:420px;width:100%}\n.admconfirm__title{font-family:var(--font-display);font-style:italic;font-size:23px;color:var(--terre);margin-bottom:8px}\n.admconfirm__msg{font-family:var(--font-body);font-size:14px;line-height:1.5;color:var(--terre-600)}\n.admconfirm__detail{margin-top:12px;padding:11px 14px;background:var(--surface-2);border-radius:12px;font-family:var(--font-micro);font-size:12px;color:var(--terre)}\n.admconfirm__row{display:flex;justify-content:flex-end;gap:10px;margin-top:22px}\n.emailvar{font-family:var(--font-micro);font-size:11px;background:var(--glycine-50);color:var(--glycine-900);padding:2px 7px;border-radius:6px;letter-spacing:0.02em}\n.grid{display:grid;gap:16px}\n.grid--3{grid-template-columns:repeat(auto-fill,minmax(240px,1fr))}\n.grid--2{grid-template-columns:1fr 1fr}\n@media(max-width:760px){.grid--2{grid-template-columns:1fr}.side{display:none}.wrap{padding:8px 16px 70px}.topbar{padding:16px 18px 12px}}\n.tile{background:var(--card);border-radius:var(--radius);padding:22px;cursor:pointer;box-shadow:var(--shadow-1);transition:transform .15s,box-shadow .15s}\n.tile:hover{transform:translateY(-2px);box-shadow:var(--shadow-2)}\n.tile .t{font-family:var(--font-display);font-style:italic;font-size:21px;color:var(--terre)}\n.tile .m{font-size:13px;color:var(--muted);margin-top:4px}\n.ctile{background:var(--card);border-radius:var(--radius);padding:20px 20px 18px;cursor:pointer;box-shadow:var(--shadow-1);transition:transform .15s,box-shadow .15s;display:flex;flex-direction:column;gap:12px}\n.ctile:hover{transform:translateY(-2px);box-shadow:var(--shadow-2)}\n.ctile__top{display:flex;align-items:center;gap:13px}\n.ctile__av{width:46px;height:46px;border-radius:50%;background:var(--terre);color:var(--paille);font-family:var(--font-display);font-style:italic;font-size:19px;display:flex;align-items:center;justify-content:center;flex-shrink:0;letter-spacing:0.02em}\n.ctile__id{flex:1;min-width:0}\n.ctile__name{font-family:var(--font-display);font-style:italic;font-size:20px;color:var(--terre);line-height:1.15;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}\n.ctile__co{font-family:var(--font-micro);font-size:10.5px;letter-spacing:0.06em;color:var(--muted);text-transform:uppercase;margin-top:3px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}\n.ctile__dot{width:9px;height:9px;border-radius:50%;background:var(--terre-200);flex-shrink:0}\n.ctile__dot.on{background:var(--green);box-shadow:0 0 0 3px rgba(93,122,82,0.14)}\n.ctile__meta{font-size:13px;color:var(--terre-600);overflow:hidden;text-overflow:ellipsis;white-space:nowrap}\n.ctile__foot{display:flex;gap:7px;flex-wrap:wrap;margin-top:auto}\n.muted{color:var(--muted)}\n.empty{text-align:center;color:var(--muted);padding:26px;font-size:14px}\n\n/* tables */\ntable{width:100%;border-collapse:collapse}\nth,td{text-align:left;padding:11px 12px;border-bottom:1px solid rgba(65,47,33,0.07);font-size:14px;vertical-align:top}\nth{font-family:var(--font-micro);font-size:10px;letter-spacing:0.06em;text-transform:uppercase;color:var(--muted);font-weight:600}\n\n/* tabs (pilules, sans soulignement) */\n.tabs{display:flex;gap:6px;flex-wrap:wrap;margin-bottom:22px}\n.tab{padding:9px 17px;border:none;background:none;cursor:pointer;font-family:var(--font-micro);font-size:11px;letter-spacing:0.06em;text-transform:uppercase;color:var(--muted);border-radius:999px;transition:background .15s,color .15s}\n.tab:hover{color:var(--terre)}\n.tab.active{color:var(--paille);background:var(--terre)}\n.subtabs{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:20px}\n.subtab{padding:8px 16px;border-radius:999px;border:none;background:var(--surface-2);color:var(--muted);cursor:pointer;font-family:var(--font-micro);font-size:11px;letter-spacing:0.05em;text-transform:uppercase;transition:color .15s,background .15s}\n.subtab:hover{color:var(--terre)}\n.subtab.active{background:var(--terre);color:var(--paille)}\n\n/* prioritÃĐs : KPIs + lignes */\n.kpis{display:grid;grid-template-columns:repeat(4,1fr);gap:14px;margin-bottom:22px}\n.kpi{background:var(--card);border-radius:16px;padding:20px 22px;box-shadow:var(--shadow-1)}\n.kpi--clic{cursor:pointer;transition:transform .15s,box-shadow .15s}\n.kpi--clic:hover{transform:translateY(-2px);box-shadow:var(--shadow-2)}\n.kpi__n{font-family:var(--font-display);font-size:38px;color:var(--terre);line-height:1}\n.kpi__l{font-family:var(--font-micro);font-size:10px;letter-spacing:0.09em;text-transform:uppercase;color:var(--terre);opacity:0.5;margin-top:7px}\n.kpi--late .kpi__n{color:#a23c28}\n.kpi--today .kpi__n{color:#b07d15}\n.kpi--week .kpi__n{color:#5e3fa0}\n.kpi--wait .kpi__n{color:#3f6ea5}\n.kpi--done .kpi__n{color:#5d7a52}\n\n/* Focus du jour : bloc marron (hÃĐros) */\n.focusband{background:var(--terre);color:var(--paille);border-radius:var(--radius);padding:22px 24px;margin-bottom:22px;box-shadow:var(--shadow-2)}\n.focusband__h{display:flex;align-items:center;gap:10px;font-family:var(--font-display);font-style:italic;font-size:23px;color:var(--paille);margin-bottom:14px}\n.focusband__ic{display:none}\n.focusband__c{margin-left:auto;font-family:var(--font-micro);font-size:12px;font-weight:700;background:var(--paille);color:var(--terre);min-width:26px;height:26px;border-radius:999px;display:inline-flex;align-items:center;justify-content:center}\n.focusrow{display:flex;gap:12px;align-items:flex-start;padding:13px 15px;border-radius:12px;margin-bottom:9px;background:rgba(242,229,194,0.09)}\n.focusrow:last-child{margin-bottom:0}\n.focusband--clear{background:var(--card);color:var(--green);font-family:var(--font-display);font-style:italic;font-size:18px;display:flex;align-items:center;gap:10px}\n\n/* listes de prioritÃĐ */\n.pgroup{margin:0 0 4px}\n.pgroup__h{display:flex;align-items:center;gap:9px;margin:20px 0 6px}\n.pgroup__t{font-family:var(--font-micro);font-size:11px;letter-spacing:0.1em;text-transform:uppercase;color:var(--terre);opacity:0.75}\n.pgroup__c{font-family:var(--font-micro);font-size:10px;color:var(--muted)}\n.pdot{display:none}\n.prow{display:flex;align-items:center;gap:14px;padding:12px 4px}\n.prow+.prow{box-shadow:inset 0 1px 0 rgba(65,47,33,0.06)}\n.prow__date{width:150px;flex-shrink:0;display:flex;flex-direction:column;line-height:1.3}\n.prow__date strong{font-family:var(--font-body);font-size:15px;color:var(--terre)}\n.prow__date span{font-family:var(--font-micro);font-size:10px;letter-spacing:0.03em;text-transform:uppercase;margin-top:2px}\n.prow__main{flex:1;min-width:0}\n.prow__el{font-size:14.5px;color:var(--terre);overflow:hidden;text-overflow:ellipsis;white-space:nowrap}\n.prow__meta{font-size:12px;color:var(--muted);margin-top:2px}\n.prow__meta a{color:var(--glycine-900)}\n.pcols{display:grid;grid-template-columns:1.55fr 1fr;gap:22px;align-items:start}\n@media(max-width:900px){.pcols{grid-template-columns:1fr}}\n.prow__act{display:flex;align-items:center;gap:6px;flex-shrink:0}\n.pbtn{font-family:var(--font-micro);font-size:9.5px;letter-spacing:0.04em;text-transform:uppercase;padding:6px 11px;border-radius:9px;border:none;background:var(--surface-2);color:var(--terre);cursor:pointer;white-space:nowrap;transition:background .15s}\n.pbtn:hover{background:var(--paille-200)}\n.pbtn--ok{background:rgba(93,122,82,0.14);color:var(--green)}\n.pbtn--ok:hover{background:rgba(93,122,82,0.22)}\n.focusrow .pbtn{background:rgba(242,229,194,0.16);color:var(--paille)}\n.focusrow .pbtn:hover{background:rgba(242,229,194,0.28)}\n.focusrow .pbtn--ok{background:var(--paille);color:var(--terre)}\n.focusrow a{color:var(--paille)}\n\n/* badges / pills */\n.pill{display:inline-block;font-family:var(--font-micro);font-size:10px;padding:3px 10px;border-radius:999px;letter-spacing:0.04em;text-transform:uppercase;background:var(--surface-2);color:var(--muted)}\n.pill--todo{background:var(--glycine-50);color:var(--glycine-900)}\n.pill--in_progress{background:var(--glycine-50);color:var(--glycine-900)}\n.pill--review,.pill--waiting_client{background:#f6ead0;color:#a8791c}\n.pill--done{background:rgba(93,122,82,0.15);color:var(--green)}\n.pill--late{background:rgba(155,58,46,0.11);color:var(--red)}\n.pill--a_valider{background:#f6ead0;color:#a8791c}\n.pill--valide{background:rgba(93,122,82,0.15);color:var(--green)}\n.pill--refuse{background:rgba(155,58,46,0.11);color:var(--red)}\n\n/* forfait bar */\n.bar{height:8px;background:var(--surface-2);border-radius:999px;overflow:hidden;margin-top:6px}\n.bar>span{display:block;height:100%;background:var(--glycine-700);border-radius:999px}\n.bar.over>span{background:var(--red)}\n\n/* chat */\n.msgs{display:flex;flex-direction:column;gap:14px;max-height:440px;overflow-y:auto;padding:6px 2px;margin-bottom:14px}\n.msg{display:flex;gap:10px;max-width:80%}\n.msg--client{align-self:flex-start}\n.msg--cindy{align-self:flex-end;flex-direction:row-reverse}\n.bubble{padding:11px 15px;border-radius:16px;font-size:15px;line-height:1.5;white-space:pre-wrap}\n.msg--client .bubble{background:var(--brume);color:var(--terre);border-top-left-radius:5px}\n.msg--cindy .bubble{background:var(--terre);color:var(--paille);border-top-right-radius:5px}\n.bmeta{font-family:var(--font-micro);font-size:9.5px;color:var(--muted);margin-top:5px;text-transform:uppercase;letter-spacing:0.04em}\n.msg--cindy .bmeta{text-align:right}\n.aavatar{width:36px;height:36px;border-radius:50%;display:grid;place-items:center;font-family:var(--font-display);font-style:italic;font-size:15px;flex-shrink:0}\n.aavatar--cindy{background:var(--terre);color:var(--paille)}\n.aavatar--client{background:var(--glycine);color:var(--terre)}\n.chatwrap{display:flex;gap:18px;height:calc(100vh - 150px);min-height:460px;align-items:stretch}\n.chatlist{width:290px;flex-shrink:0;background:var(--card);border-radius:var(--radius);display:flex;flex-direction:column;overflow:hidden;box-shadow:var(--shadow-1)}\n.chatlist__head{padding:18px 20px;flex-shrink:0}\n.chatlist__scroll{flex:1;overflow-y:auto;padding:10px}\n.chatperson{display:flex;align-items:center;gap:11px;padding:10px 11px;border-radius:12px;cursor:pointer;border:none;width:100%;text-align:left;background:none;margin-bottom:2px;transition:background .15s}\n.chatperson:hover{background:var(--surface-2)}\n.chatperson.active{background:var(--brume)}\n.chatperson.unread{background:#f7edda}\n.chatperson__nm{flex:1;min-width:0;font-family:var(--font-body);font-size:14px;color:var(--terre);white-space:nowrap;overflow:hidden;text-overflow:ellipsis}\n.chatpane{flex:1;min-width:0;background:var(--card);border-radius:var(--radius);display:flex;flex-direction:column;overflow:hidden;box-shadow:var(--shadow-1)}\n.chathead{padding:17px 22px;display:flex;align-items:center;gap:12px;flex-shrink:0;box-shadow:inset 0 -1px 0 rgba(65,47,33,0.07)}\n.chathead__t{font-family:var(--font-display);font-style:italic;font-size:21px;color:var(--terre)}\n.chathead__s{font-family:var(--font-micro);font-size:10px;color:var(--muted);letter-spacing:0.05em;margin-top:1px}\n.chatbody{flex:1;min-height:0;display:flex;flex-direction:column;padding:0}\n.chatscroll{flex:1;overflow-y:auto;padding:24px;display:flex;flex-direction:column;gap:14px}\n.chatcompose{padding:16px 20px;display:flex;gap:10px;align-items:flex-end;flex-shrink:0;box-shadow:inset 0 1px 0 rgba(65,47,33,0.07)}\n.chatcompose textarea{flex:1;resize:none;min-height:48px;max-height:300px;overflow-y:auto;line-height:1.5}\n.chatchips{display:flex;gap:6px;flex-wrap:wrap;padding:12px 22px 0}\n\n/* layout helpers */\n.row{display:flex;gap:10px;align-items:center;flex-wrap:wrap}\n.row--end{justify-content:flex-end}\n.between{display:flex;justify-content:space-between;align-items:center;gap:10px}\n.mt{margin-top:16px}.mb{margin-bottom:12px}\n.keybox{font-family:monospace;background:var(--surface-2);border-radius:10px;padding:11px 13px;word-break:break-all;font-size:14px}\n.toast{position:fixed;bottom:24px;left:50%;transform:translateX(-50%) translateY(90px);background:var(--terre);color:var(--paille);padding:12px 24px;border-radius:999px;font-family:var(--font-micro);font-size:12px;letter-spacing:0.06em;text-transform:uppercase;z-index:999;transition:transform .3s;box-shadow:var(--shadow-2)}\n.toast.show{transform:translateX(-50%) translateY(0)}\n.file{display:flex;align-items:center;gap:10px;padding:11px 13px;border-radius:11px;margin-bottom:7px;background:var(--surface-2)}\n.file .nm{flex:1;font-size:14px;word-break:break-all}\n.checkbox{display:flex;align-items:center;gap:8px;font-size:14px;color:var(--text)}\n\n/* ââ finitions globales ââ */\nhtml{-webkit-text-size-adjust:100%;scroll-behavior:smooth}\nbody{-webkit-font-smoothing:antialiased;-moz-osx-font-smoothing:grayscale;text-rendering:optimizeLegibility}\n::selection{background:var(--glycine);color:var(--terre)}\n:focus-visible{outline:2px solid var(--glycine-700);outline-offset:2px;border-radius:6px}\n.inp:focus-visible{outline:none}\na{text-decoration:none;transition:color .15s,opacity .15s}\na:hover{opacity:0.78}\nbutton{-webkit-tap-highlight-color:transparent}\ninput,textarea,select{accent-color:var(--terre)}\ninput[type=checkbox]{width:16px;height:16px;cursor:pointer}\n/* barres de dÃĐfilement discrÃĻtes, dans la charte */\n*{scrollbar-width:thin;scrollbar-color:var(--terre-200) transparent}\n::-webkit-scrollbar{width:10px;height:10px}\n::-webkit-scrollbar-track{background:transparent}\n::-webkit-scrollbar-thumb{background:var(--terre-200);border-radius:999px;border:3px solid transparent;background-clip:content-box}\n::-webkit-scrollbar-thumb:hover{background:var(--terre-400)}\n.side ::-webkit-scrollbar-thumb,.side::-webkit-scrollbar-thumb{background:rgba(242,229,194,0.28);background-clip:content-box}\n@media (prefers-reduced-motion:reduce){*{animation-duration:.001ms!important;transition-duration:.001ms!important;scroll-behavior:auto}}\n";
