      // par le client sur son espace.\n      function prioTimer(x, dark) {\n        if (!x.id) return '';\n        // Tickets : saisie manuelle du temps passÃĐ (pas de chrono live inter-clients ici).\n        if (x.kind === 'ticket' || x.project === 'maintenance') {\n          var tsec = x.timeSpentSeconds || (x.timeSpentMinutes || 0) * 60;\n          var tcol = dark ? 'rgba(242,229,194,0.85)' : 'var(--terre)';\n          var tclock = '<span title=\"Temps passÃĐ sur ce ticket\" style=\"font-family:var(--font-micro);font-variant-numeric:tabular-nums;font-weight:700;font-size:13px;color:' + tcol + ';min-width:54px;text-align:right\">' + mtClock(tsec) + '</span>';\n          var tedit = '<button class=\"pbtn\" title=\"Saisir le temps passÃĐ sur ce ticket\" onclick=\"ADM.prioSetTime(\\'' + x.key + '\\',\\'' + x.id + '\\',' + tsec + ',\\'ticket\\',\\'' + (x.project || 'maintenance') + '\\')\">â</button>';\n          return '<span style=\"display:inline-flex;align-items:center;gap:5px\">' + tclock + tedit + '</span>';\n        }\n        if (x.project !== 'partner') return '';\n        var run = PT_TIMER && PT_TIMER.id === x.id;\n        var sec = run ? (PT_TIMER.base + (Date.now() - PT_TIMER.startedAt) / 1000) : (x.timeSpentSeconds || 0);\n        var col = run ? 'var(--green)' : (dark ? 'rgba(242,229,194,0.85)' : 'var(--terre)');\n        var clock = '<span id=\"pt-timer-' + x.id + '\" title=\"Temps passÃĐ sur cette tÃĒche\" style=\"font-family:var(--font-micro);font-variant-numeric:tabular-nums;font-weight:700;font-size:13px;color:' + col + ';min-width:54px;text-align:right\">' + mtClock(sec) + '</span>';\n        var btn = run\n          ? '<button class=\"pbtn\" style=\"color:var(--orange)\" title=\"Mettre le chrono en pause\" onclick=\"ADM.ptPause(\\'' + x.id + '\\')\">âļ</button>'\n          : '<button class=\"pbtn\" title=\"DÃĐmarrer le chrono\" onclick=\"ADM.ptStart(\\'' + x.id + '\\',\\'' + x.key + '\\')\">âķ</button>';\n        // Saisie manuelle du temps 